B.Ts=s(["\u0110\u1ee1 n\u1ed5i {skill} c\u1ee7a ta kh\xf4ng?","T\u1edbi l\xfac ta tung {skill} r\u1ed3i.","{skill} n\xe0y s\u1ebd kh\xf3a \u0111\u01b0\u1eddng lui c\u1ee7a ng\u01b0\u01a1i.","Ta s\u1ebd ph\u1ea3i tung {skill} n\xe0y.","{skill} b\u1eafn tung l*n ng\u01b0\u01a1i.","{skill} .","Ta s\u1ebd tung k\u1ef9 n\u0103ng gia truy\u1ec1n: {skill}","\xdam ba la s\xec l\xe0 b\xf9a {skill}"],t.s)
